interface ExecOptions {
  readonly cwd?: string;
  readonly timeoutMs?: number;
  /** Additional environment variables to pass to the subprocess */
  readonly env?: Record<string, string>;
}

function shellEscapePath(value: string): string {
  if (process.platform === 'win32') {
    // Very small escape helper for file paths in cmd.exe context.
    // Wrap in double-quotes and escape existing double-quotes.
    return `"${value.replaceAll('"', '""')}"`;
  }
  // POSIX: single-quote escape (close/open around embedded single quotes).
  return `'${value.replaceAll("'", `'\"'\"'`)}'`;
}

// IPC protocol: stdin/stdout JSON was chosen over JSON-RPC (overkill for one-shot eval),
// HTTP (unnecessary network overhead for local scripts), and in-process (no isolation,
// single-language only). Each evaluation is isolated by design for reproducibility and
// safe parallelization. Process spawn overhead (~10-50ms) is acceptable for eval workloads.
export async function execFileWithStdin(
  argv: readonly string[],
  stdinPayload: string,
  options: ExecOptions = {},
): Promise<{
  readonly stdout: string;
  readonly stderr: string;
  readonly exitCode: number;
}> {
  if (argv.length === 0) {
    throw new Error('Executable argv must include at least one entry');
  }

  // Use Node's child_process path even under Bun. Bun 1.3.3 can hang when a
  // Bun.spawn child is a Node process reading stdin, which breaks code grader
  // and workspace hook execution on CI's pinned Bun version.
  return execFileWithStdinNode(argv, stdinPayload, options);
}

/**
 * Node.js implementation using child_process.spawn
 */
async function execFileWithStdinNode(
  argv: readonly string[],
  stdinPayload: string,
  options: ExecOptions,
): Promise<{
  readonly stdout: string;
  readonly stderr: string;
  readonly exitCode: number;
}> {
  const { spawn } = await import('node:child_process');

  return new Promise((resolve, reject) => {
    const [cmd, ...args] = argv;
    const child = spawn(cmd, args, {
      cwd: options.cwd,
      stdio: ['pipe', 'pipe', 'pipe'],
      // Merge additional env vars with process.env
      env: options.env ? { ...process.env, ...options.env } : process.env,
    });

    const stdoutChunks: Buffer[] = [];
    const stderrChunks: Buffer[] = [];

    child.stdout?.on('data', (chunk: Buffer) => stdoutChunks.push(chunk));
    child.stderr?.on('data', (chunk: Buffer) => stderrChunks.push(chunk));

    let timedOut = false;
    const timeout =
      options.timeoutMs !== undefined
        ? setTimeout(() => {
            timedOut = true;
            child.kill('SIGKILL');
          }, options.timeoutMs)
        : undefined;

    child.on('error', (error) => {
      if (timeout !== undefined) clearTimeout(timeout);
      reject(error);
    });

    child.on('close', (code) => {
      if (timeout !== undefined) clearTimeout(timeout);

      if (timedOut) {
        reject(new Error(`Process timed out after ${options.timeoutMs}ms`));
        return;
      }

      const stdout = Buffer.concat(stdoutChunks).toString('utf8').replace(/\r\n/g, '\n');
      const stderr = Buffer.concat(stderrChunks).toString('utf8').replace(/\r\n/g, '\n');

      resolve({
        stdout,
        stderr,
        exitCode: code ?? 0,
      });
    });

    // Write stdin and close
    if (child.stdin) {
      child.stdin.write(stdinPayload);
      child.stdin.end();
    }
  });
}

