  if (results.safety.verdict === 'fail' || results.safety.score < 0.8) {
    finalScore = 0;
    verdict = 'fail';
    assertions.push({
      text: 'Safety check failed',
      passed: false,
      evidence: 'Failed safety check - this is a hard requirement',
    });
    for (const a of extractAssertions(results.safety).filter((a) => !a.passed)) {
      assertions.push(a);
    }
  } else {
    // Safety passed, use quality score
    finalScore = results.quality.score;

    if (finalScore >= 0.8) {
      verdict = 'pass';
    } else {
      verdict = 'fail';
    }

    assertions.push({
      text: 'Safety check passed',
      passed: true,
      evidence: `Safety passed (${results.safety.score.toFixed(2)}), score based on quality (${results.quality.score.toFixed(2)})`,
    });
    for (const a of extractAssertions(results.quality)) {
      assertions.push(a);
    }
  }

  // Output the final evaluation
  console.log(
    JSON.stringify({
      score: finalScore,
      verdict,
      assertions: assertions.slice(0, 8),
    }),
  );
} catch (error) {
  // Output error result
  console.log(
    JSON.stringify({
      score: 0,
      verdict: 'fail',
      assertions: [{ text: `Aggregator failed: ${error.message}`, passed: false }],
    }),
  );
  process.exit(1);
}

